function solve(nums, target) {
    const N = nums.length;

    // Handle empty input case, although constraints say N >= 1
    if (N === 0) {
        return target === 0 ? 0 : -1;
    }

    const N_A = Math.floor(N / 2);
    const A = nums.slice(0, N_A);
    const B = nums.slice(N_A);
    const N_B = N - N_A;

    // MapA stores {xor_sum: max_size} for subsets of A
    // Max size is used because we want to maximize the total retained size.
    const MapA = new Map();

    // 1. Process Half A (Complexity O(2^(N/2)))
    // Iterate through all 2^N_A subsets using bitmasks
    for (let i = 0; i < (1 << N_A); i++) {
        let xorSum = 0;
        let size = 0;

        for (let j = 0; j < N_A; j++) {
            if ((i >> j) & 1) {
                xorSum ^= A[j];
                size++;
            }
        }

        // Update MapA to store the maximum size found for this xorSum
        const currentMax = MapA.get(xorSum) || -1;
        if (size > currentMax) {
            MapA.set(xorSum, size);
        }
    }

    // 2. Process Half B and find maximum total size K_max (Complexity O(2^(N/2)))
    let K_max = -1;

    // Iterate through all 2^N_B subsets using bitmasks
    for (let i = 0; i < (1 << N_B); i++) {
        let xorSumB = 0;
        let sizeB = 0;

        for (let j = 0; j < N_B; j++) {
            if ((i >> j) & 1) {
                xorSumB ^= B[j];
                sizeB++;
            }
        }

        // We require xorSumA ^ xorSumB = target
        // => xorSumA = target ^ xorSumB
        const xorSumA_req = target ^ xorSumB;

        if (MapA.has(xorSumA_req)) {
            const sizeA = MapA.get(xorSumA_req);
            const totalSize = sizeA + sizeB;

            if (totalSize > K_max) {
                K_max = totalSize;
            }
        }
    }

    // 3. Determine minimum removals
    if (K_max === -1) {
        return -1;
    } else {
        // Minimum removals = Total elements - Maximum retained elements
        return N - K_max;
    }
}

